// `Env` is generated by `wrangler types` (npm run cf-typegen) from wrangler.jsonc
// into worker-configuration.d.ts - do not hand-write the binding shape here.

import {
  getMarketplaceCatalog,
  getMarketplaceMetadata,
  getMarketplaceModuleById,
  getMarketplaceModules,
  getMarketplaceStatuses,
} from "./authoritativeMarketplaceAdapter";
import { handleAuthRoute } from "./auth";
import { handleEngineRoute } from "./engine";
import { handleWebhookRoute } from "./webhookTrigger";
import { handleSecurityRoute } from "./security";
import { handleTtxRoute } from "./ttx";
import { handleNewsReelRoute } from "./newsReel";

const API_PREFIX = "/api/";
const CATALOG_PATH = "/api/marketplace/catalog";
const MODULES_PATH = "/api/modules";
const MODULES_STATUS_PATH = "/api/modules/status";
const MODULES_METADATA_PATH = "/api/modules/metadata";
const AUTH_PREFIX = "/api/auth/";
const ENGINE_PREFIX = "/api/engine/";
const WEBHOOK_PREFIX = "/api/webhooks/";
const SECURITY_PREFIX = "/api/security/";
const TTX_PREFIX = "/api/ttx/";

const RATE_LIMIT_WINDOW_MS = 60_000;
const RATE_LIMIT_MAX_REQUESTS = 60;

const rateLimitBuckets = new Map<string, { count: number; windowStart: number }>();

function isRateLimited(clientId: string): boolean {
  const now = Date.now();
  const bucket = rateLimitBuckets.get(clientId);

  if (!bucket || now - bucket.windowStart >= RATE_LIMIT_WINDOW_MS) {
    rateLimitBuckets.set(clientId, { count: 1, windowStart: now });
    return false;
  }

  bucket.count += 1;
  return bucket.count > RATE_LIMIT_MAX_REQUESTS;
}

export default {
  async fetch(request, env): Promise<Response> {
    const url = new URL(request.url);

    if (url.pathname.startsWith(API_PREFIX)) {
      const clientId = request.headers.get("CF-Connecting-IP") ?? "unknown";
      if (isRateLimited(clientId)) {
        return Response.json(
          { error: "Rate limit exceeded - try again shortly" },
          { status: 429, headers: { "Retry-After": String(RATE_LIMIT_WINDOW_MS / 1000) } },
        );
      }

      if (url.pathname === CATALOG_PATH) {
        return await serveCatalog(request, env);
      }

      if (url.pathname === MODULES_PATH) {
        return await serveModules(request, env);
      }

      if (url.pathname === MODULES_STATUS_PATH) {
        return await serveModuleStatus(request, env);
      }

      if (url.pathname === MODULES_METADATA_PATH) {
        return await serveModuleMetadata(request, env);
      }

      if (url.pathname.startsWith(`${MODULES_PATH}/`)) {
        return await serveModuleDetail(request, env, url.pathname);
      }

      if (url.pathname.startsWith(ENGINE_PREFIX)) {
        const engineResponse = handleEngineRoute(request, url.pathname, env);
        if (engineResponse) return engineResponse;
      }

      if (url.pathname.startsWith(WEBHOOK_PREFIX)) {
        const webhookResponse = await handleWebhookRoute(request, url.pathname, env);
        if (webhookResponse) return webhookResponse;
      }

      if (url.pathname.startsWith(SECURITY_PREFIX)) {
        const securityResponse = await handleSecurityRoute(request, url.pathname, env);
        if (securityResponse) return securityResponse;
      }

      if (url.pathname.startsWith(TTX_PREFIX)) {
        const ttxResponse = await handleTtxRoute(request, url.pathname, env);
        if (ttxResponse) return ttxResponse;
      }

      if (url.pathname.startsWith(AUTH_PREFIX)) {
        const authResponse = await handleAuthRoute(request, url.pathname, env);
        if (authResponse) return authResponse;
      }

      const newsReelResponse = handleNewsReelRoute(request);
      if (newsReelResponse) return newsReelResponse;

      return proxyToEngine(request, url, env);
    }

    return serveAsset(request, env, url);
  },
} satisfies ExportedHandler<Env>;

async function serveAsset(request: Request, env: Env, url: URL): Promise<Response> {
  if (!url.pathname.startsWith("/ops")) {
    return env.ASSETS.fetch(request);
  }

  const assetUrl = new URL(request.url);
  assetUrl.pathname = stripOpsPrefix(url.pathname);

  const assetResponse = await env.ASSETS.fetch(new Request(assetUrl, request));
  const contentType = assetResponse.headers.get("Content-Type") ?? "";
  if (!contentType.includes("text/html")) {
    return assetResponse;
  }

  const html = await assetResponse.text();
  const rewrittenHtml = html.replaceAll('href="/', 'href="/ops/').replaceAll('src="/', 'src="/ops/');
  const headers = new Headers(assetResponse.headers);
  headers.set("Content-Length", String(new TextEncoder().encode(rewrittenHtml).byteLength));
  return new Response(rewrittenHtml, {
    status: assetResponse.status,
    statusText: assetResponse.statusText,
    headers,
  });
}

function stripOpsPrefix(pathname: string): string {
  if (pathname === "/ops" || pathname === "/ops/") {
    return "/";
  }

  return pathname.startsWith("/ops/") ? pathname.slice("/ops".length) : pathname;
}

async function serveCatalog(request: Request, env: Env): Promise<Response> {
  if (request.method !== "GET") {
    return Response.json({ error: "Method not allowed" }, { status: 405, headers: { Allow: "GET" } });
  }

  const headers = buildMarketplaceHeaders(request);
  const items = await getMarketplaceCatalog(request, env);
  return new Response(JSON.stringify({ items }), { status: 200, headers });
}

async function serveModules(request: Request, env: Env): Promise<Response> {
  if (request.method !== "GET") {
    return Response.json({ error: "Method not allowed" }, { status: 405, headers: { Allow: "GET" } });
  }

  const headers = buildMarketplaceHeaders(request);
  const modules = await getMarketplaceModules(request, env);
  return new Response(JSON.stringify({ modules }), { status: 200, headers });
}

async function serveModuleStatus(request: Request, env: Env): Promise<Response> {
  if (request.method !== "GET") {
    return Response.json({ error: "Method not allowed" }, { status: 405, headers: { Allow: "GET" } });
  }

  const headers = buildMarketplaceHeaders(request);
  const status = await getMarketplaceStatuses(request, env);
  return new Response(JSON.stringify({ status }), { status: 200, headers });
}

async function serveModuleMetadata(request: Request, env: Env): Promise<Response> {
  if (request.method !== "GET") {
    return Response.json({ error: "Method not allowed" }, { status: 405, headers: { Allow: "GET" } });
  }

  const headers = buildMarketplaceHeaders(request);
  const metadata = await getMarketplaceMetadata(request, env);
  return new Response(JSON.stringify({ metadata }), { status: 200, headers });
}

async function serveModuleDetail(request: Request, env: Env, pathname: string): Promise<Response> {
  if (request.method !== "GET") {
    return Response.json({ error: "Method not allowed" }, { status: 405, headers: { Allow: "GET" } });
  }

  const moduleId = pathname.slice(`${MODULES_PATH}/`.length);
  const moduleRecord = await getMarketplaceModuleById(request, env, moduleId);
  if (!moduleRecord) {
    return Response.json({ error: "Module not found" }, { status: 404 });
  }

  const headers = buildMarketplaceHeaders(request);
  return new Response(JSON.stringify(moduleRecord), { status: 200, headers });
}

function buildMarketplaceHeaders(request: Request): Headers {
  const headers = new Headers({ "Content-Type": "application/json" });
  headers.set("X-Auth-Token-Present", String(request.headers.has("Authorization")));
  const role = request.headers.get("X-Operator-Role");
  const accessLevel = request.headers.get("X-Operator-Access-Level");
  if (role) headers.set("X-Operator-Role-Received", role);
  if (accessLevel) headers.set("X-Operator-Access-Level-Received", accessLevel);
  return headers;
}

async function proxyToEngine(request: Request, url: URL, env: Env): Promise<Response> {
  if (!env.ENGINE_API_URL) {
    return Response.json({ error: "ENGINE_API_URL is not configured" }, { status: 503 });
  }

  let target: URL;
  try {
    target = new URL(url.pathname + url.search, env.ENGINE_API_URL);
  } catch {
    return Response.json({ error: "ENGINE_API_URL is not a valid URL" }, { status: 500 });
  }

  const upstreamRequest = new Request(target, request);
  upstreamRequest.headers.set("X-Forwarded-Host", url.host);
  upstreamRequest.headers.set("X-Forwarded-Proto", url.protocol.replace(":", ""));

  try {
    const upstreamResponse = await fetch(upstreamRequest);
    const response = new Response(upstreamResponse.body, upstreamResponse);
    response.headers.set("X-Proxied-By", "mshops-storefront-worker");
    return response;
  } catch (err) {
    return Response.json(
      {
        error: "Engine API unreachable",
        detail: err instanceof Error ? err.message : String(err),
      },
      { status: 502 },
    );
  }
}
